function saturdaysOfYear(){let y=new Date().getFullYear(),d=new Date(y,0,1),arr=[];while(d.getFullYear()===y){if(d.getDay()===6)arr.push(new Date(d));d.setDate(d.getDate()+1)}return arr.slice(0,52)}
function cateWeekIndex(date=new Date()){let sats=saturdaysOfYear();let idx=sats.findIndex(s=>iso(s)>=iso(date));return idx<0?51:idx}
