function studyPercent(sub){
 let v=state.academyStats[sub]||{correct:0,total:0};
 let score=v.total?Math.round((v.correct/v.total)*100):0;
 let grade=state.grades[sub]?Math.round(avg(state.grades[sub])*10):50;
 return Math.max(10, Math.min(100, Math.round((score+grade)/2)));
}


function shuffleArray(arr){return [...arr].sort(()=>Math.random()-0.5)}
function getQuestionDifficulty(q){return (q[5]||'facil').toLowerCase()}
function startAcademySession(){
 const sub=(document.getElementById('disciplineSelect')?.value)||state.selectedSubject||smartPriority();
 const count=Number(document.getElementById('questionCountSelect')?.value||10);
 const difficulty=(document.getElementById('difficultySelect')?.value)||'misto';
 let pool=(questionBank[sub]||[]).map((q,i)=>({q,i}));
 if(difficulty!=='misto') pool=pool.filter(x=>getQuestionDifficulty(x.q)===difficulty);
 if(!pool.length){
   alert('Não há perguntas disponíveis para essa disciplina e dificuldade.');
   return;
 }
 let selected=shuffleArray(pool);
 if(count <= selected.length){
   selected = selected.slice(0,count);
 }else{
   const expanded=[];
   while(expanded.length < count){
     expanded.push(...shuffleArray(pool));
   }
   selected = expanded.slice(0,count);
 }
 state.selectedSubject=sub;
 state.academySession={
   id:'session-'+Date.now(),
   date:today(),
   subject:sub,
   requested:count,
   difficulty,
   questions:selected.map(x=>x.i),
   current:0,
   correct:0,
   total:selected.length,
   answered:[]
 };
 save();
 renderAcademySession();
}
function renderAcademySession(){
 const box=document.getElementById('academySessionStatus');
 if(!box) return;
 const s=state.academySession;
 if(!s){
   box.innerHTML='<b>Academia V35.2:</b> escolha disciplina, quantidade e dificuldade para iniciar um treino.';
   return;
 }
 const sub=s.subject, bank=questionBank[sub]||[];
 if(s.current>=s.questions.length){
   const pct=s.total?Math.round((s.correct/s.total)*100):0;
   const xpGain=s.correct*5;
   box.innerHTML=`<b>Treino concluído!</b><br>${icons[sub]||'📚'} ${sub}<br><b>${s.correct}/${s.total}</b> acertos • ${pct}% • +${xpGain} XP`;
   quiz.innerHTML=`<div class="details"><b>Resultado final</b><br>Disciplina: ${sub}<br>Quantidade: ${s.total}<br>Acertos: ${s.correct}<br>Erros: ${s.total-s.correct}<br>XP conquistado: ${xpGain}</div><button id="startAcademySession">Novo treino</button>`;
   return;
 }
 const idx=s.questions[s.current], q=bank[idx];
 box.innerHTML=`<b>Treino em andamento:</b> ${icons[sub]||'📚'} ${sub}<br>Questão ${s.current+1}/${s.total} • Acertos: ${s.correct}`;
 quiz.innerHTML=`<h3>${icons[sub]||'📚'} ${sub}</h3>
 <p><b>Questão ${s.current+1}:</b> ${q[0]}</p>
 <small>Tema: ${q[4]||'Geral'} • Nível: ${q[5]||'facil'}</small>
 ${q[1].map((a,i)=>`<button class="answer-session" data-i="${i}">${a}</button>`).join('')}
 <div class="feedback hidden"></div>`;
}
function answerAcademySession(choice){
 const s=state.academySession;
 if(!s) return;
 const bank=questionBank[s.subject]||[], idx=s.questions[s.current], q=bank[idx];
 const ok=Number(choice)===q[2];
 if(ok){s.correct++;state.xp+=5}
 s.answered.push({questionId:q[6]||idx,choice:Number(choice),correct:ok});
 state.academyStats[s.subject]=state.academyStats[s.subject]||{correct:0,total:0};
 state.academyStats[s.subject].total++;
 if(ok) state.academyStats[s.subject].correct++;
 s.current++;
 if(s.current>=s.questions.length){
   state.academyHistory=state.academyHistory||[];
   state.academyHistory.unshift({id:s.id,date:s.date,subject:s.subject,total:s.total,correct:s.correct,difficulty:s.difficulty,xp:s.correct*5});
   state.academyHistory=state.academyHistory.slice(0,100);
 }
 save();
 renderAcademySession();
 renderAcademyStats();
}


function renderSelectedCurriculum(selected){
 const el=document.getElementById('curriculum');
 if(!el) return;
 const sub=selected || state.selectedSubject || smartPriority();
 const bank=questionBank[sub]||[];
 const temas=[...new Set(bank.map(q=>q[4]||'Geral'))];
 const niveis=bank.reduce((acc,q)=>{let n=(q[5]||'facil');acc[n]=(acc[n]||0)+1;return acc},{});
 const lista=(curriculum[sub]||temas).map(t=>`<span class="chip">${t}</span>`).join(' ');
 el.innerHTML=`<div class="item"><b>${icons[sub]||'📚'} ${sub}</b><br><small>${bank.length} questões disponíveis</small><br><small>Fácil: ${niveis.facil||0} • Médio: ${niveis.medio||0} • Difícil: ${niveis.dificil||0}</small><div class="chip-list">${lista}</div></div>`;
}

function renderAcademy(){
 let pr=smartPriority();
 let selected=state.selectedSubject || pr;
 academyPriority.innerHTML=`<b>Prioridade inteligente:</b> ${icons[pr]||'📚'} ${pr}<br><small>Recomendação da Águia: hoje seria interessante estudar ${pr}. Mas João Miguel pode trocar e escolher qualquer disciplina.</small>`;
 if(document.getElementById('disciplineSelect')){
   disciplineSelect.innerHTML=subjects.map(s=>`<option value="${s}" ${s===selected?'selected':''}>${icons[s]||'📚'} ${s} (${(questionBank[s]||[]).length})</option>`).join('');
 }
 renderSelectedCurriculum(selected);
 subjects.innerHTML=subjects.map(s=>`<button class="subject ${s===pr?'priority':''}" data-subject="${s}">${icons[s]||'📚'} ${s}</button>`).join('');
 let bars=subjects.map(s=>{let p=studyPercent(s);return `<div class="study-row"><b>${icons[s]||'📚'} ${s}</b><div class="study-meter"><span style="width:${p}%"></span></div><small>${p}%</small></div>`}).join('');
 academyPriority.innerHTML += `<div class="study-bars">${bars}</div>`;
 renderAcademySession();
 renderAcademyStats()
}

function normalizeGrade(x){x=String(x).replace(',','.');let n=parseFloat(x);if(isNaN(n))return null;if(n>10&&n<=100)n=n/10;return Math.max(0,Math.min(10,n))}
function parseGradesFromText(text){let found={};let norm=text.normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase();for(let [alias,sub] of Object.entries(aliases)){let a=alias.normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase();let idx=norm.indexOf(a);if(idx>=0){let slice=text.slice(Math.max(0,idx-20),idx+180);let nums=[...slice.matchAll(/\b(10(?:[,.]0)?|[0-9](?:[,.][0-9])?)\b/g)].map(m=>normalizeGrade(m[1])).filter(v=>v!==null);if(nums.length)found[sub]=nums.slice(0,4)}}return found}
function applyDetectedGrades(found){let count=0;for(let [s,nums] of Object.entries(found)){if(!state.grades[s])state.grades[s]=[0,0,0,0];for(let i=0;i<Math.min(4,nums.length);i++){state.grades[s][i]=nums[i];count++}}save();renderGradesTable();return count}
function renderGradesTable(){let b=['1º bim.','2º bim.','3º bim.','4º bim.'];gradesTable.innerHTML=`<table class="grade-table"><thead><tr><th>Disciplina</th>${b.map(x=>`<th>${x}</th>`).join('')}<th>Média</th></tr></thead><tbody>`+Object.entries(state.grades).map(([sub,arr])=>`<tr><td><b>${sub}</b></td>${[0,1,2,3].map(i=>`<td><input data-grade-sub="${sub}" data-grade-i="${i}" type="number" min="0" max="10" step="0.1" value="${arr[i]||0}"></td>`).join('')}<td><b>${avg(arr).toFixed(1)}</b></td></tr>`).join('')+`</tbody></table>`;renderParentGrades();renderAcademy()}
function renderParentGrades(){parentGradesTable.innerHTML=`<table class="grade-table"><thead><tr><th>Disciplina</th><th>1º</th><th>2º</th><th>3º</th><th>4º</th><th>Média</th></tr></thead><tbody>`+Object.entries(state.grades).map(([s,arr])=>`<tr><td><b>${s}</b></td>${arr.map(n=>`<td>${Number(n||0).toFixed(1)}</td>`).join('')}<td><b>${avg(arr).toFixed(1)}</b></td></tr>`).join('')+`</tbody></table>`}
function renderAcademyStats(){
 const statSubjects=subjects;
 let html=statSubjects.map(s=>{
   let v=state.academyStats[s]||{correct:0,total:0};
   let pct=v.total?Math.round(v.correct/v.total*100):0;
   return `<div class="stat-card"><b>${icons[s]||'📚'} ${s}</b><br><small>${v.correct}/${v.total} acertos • ${pct}%</small></div>`;
 }).join('');
 let hist=(state.academyHistory||[]).slice(0,10).map(h=>`<div class="history-row"><b>${h.date}</b> — ${h.subject}: ${h.correct}/${h.total} • +${h.xp} XP</div>`).join('')||'<p class="muted">Nenhum treino registrado ainda.</p>';
 academyStats.innerHTML=`<div class="grid">${html}</div><h3>Histórico recente</h3>${hist}`;
 parentAcademyStats.innerHTML=`<div class="grid">${html}</div>${hist}`;
}
function renderAchievements(){
 const achievementEl=document.getElementById('achievementList');
 const campaignEl=document.getElementById('campaignMap');
 const summaryEl=document.getElementById('achievementSummary');
 const levelEl=document.getElementById('journeyLevel');
 if(!achievementEl || !campaignEl) return;

 const approved=approvedMissionCount();
 const tasks=completedTaskCount();
 const cateDone=cateDoneCount();
 const xpVal=Number(state.xp || 0);

 const achievements=[
  {name:'🥉 Primeira missão', done:approved>=1, need:'Aprovar a primeira missão com o responsável.', progress:approved>=1?100:0, detail:`${approved} missão(ões) aprovada(s).`},
  {name:'🎯 Missionário da Semana', done:approved>=5, need:'Aprovar 5 missões.', progress:Math.min(100, Math.round(approved/5*100)), detail:`${approved}/5 missões aprovadas.`},
  {name:'✝️ Primeiro Sábado', done:cateDone>=1, need:'Concluir a primeira lição do Catecismo.', progress:Math.min(100, cateDone*100), detail:`${cateDone} sábado(s) concluído(s).`},
  {name:'📖 Pequeno Catequista', done:cateDone>=10, need:'Concluir 10 sábados.', progress:Math.min(100, Math.round(cateDone/10*100)), detail:`${cateDone}/10 sábados.`},
  {name:'🏛 Discípulo de São Pio X', done:cateDone>=25, need:'Concluir 25 sábados.', progress:Math.min(100, Math.round(cateDone/25*100)), detail:`${cateDone}/25 sábados.`},
  {name:'🦅 Águia da Fé', done:cateDone>=52, need:'Concluir 52 sábados.', progress:Math.min(100, Math.round(cateDone/52*100)), detail:`${cateDone}/52 sábados.`}
 ];

 const unlocked=achievements.filter(a=>a.done).length;
 const total=achievements.length;
 const pct=Math.round(unlocked/total*100);

 if(summaryEl){
  summaryEl.innerHTML=`
   <div class="achievement-summary">
    <b>Progresso das conquistas: ${unlocked}/${total}</b>
    <div class="progress-line"><span style="width:${pct}%"></span></div>
    <small>${pct}% das conquistas principais desbloqueadas.</small><br>
    <small>Missões aprovadas: <b>${approved}</b> • Tarefas concluídas: <b>${tasks}</b> • Catecismo: <b>${cateDone}/52</b> • XP: <b>${xpVal}</b></small>
   </div>
  `;
 }

 achievementEl.innerHTML=achievements.map(a=>`
  <div class="achievement ${a.done?'done':'locked'}">
   <b>${a.name}</b><br>
   <small>${a.done?'Desbloqueada':('Falta: '+a.need)}</small><br>
   <small>${a.detail}</small>
   <div class="progress-line"><span style="width:${a.progress}%"></span></div>
   <small>${a.progress}%</small>
  </div>
 `).join('');

 const levels=[
  {name:'Aspirante', xp:0, note:'Começo da jornada.'},
  {name:'Escudeiro', xp:50, note:'Primeiros hábitos firmes.'},
  {name:'Estudioso', xp:100, note:'Constância nos estudos.'},
  {name:'Discípulo', xp:150, note:'Estudo com disciplina.'},
  {name:'Águia Jovem', xp:200, note:'Autonomia crescente.'},
  {name:'Guardião', xp:250, note:'Perseverança e responsabilidade.'},
  {name:'Águia Imperial', xp:300, note:'Excelência na jornada.'}
 ];

 let currentIndex=0;
 for(let i=0;i<levels.length;i++){
  if(xpVal>=levels[i].xp) currentIndex=i;
 }

 const current=levels[currentIndex];
 const next=levels[currentIndex+1];
 const nextPct=next?Math.min(100, Math.max(0, Math.round((xpVal-current.xp)/(next.xp-current.xp)*100))):100;

 if(levelEl){
  levelEl.innerHTML=`
   <div class="journey-level-card">
    <div>🦅 Nível atual</div>
    <div class="level-name">${currentIndex+1}. ${current.name}</div>
    <small>${current.note}</small><br>
    <small>${xpVal} XP acumulados</small>
    <div class="progress-line"><span style="width:${nextPct}%"></span></div>
    <div class="next-goal">${next?`Próximo nível: <b>${next.name}</b> — faltam ${Math.max(0,next.xp-xpVal)} XP.`:'Nível máximo alcançado.'}</div>
   </div>
  `;
 }

 campaignEl.innerHTML=levels.map((l,i)=>{
  const unlocked=xpVal>=l.xp;
  const currentClass=i===currentIndex?'current':'';
  const prevXp=i===0?0:levels[i-1].xp;
  const localProgress=unlocked?100:Math.max(0, Math.min(100, Math.round((xpVal-prevXp)/(l.xp-prevXp)*100)));
  return `
   <div class="campaign-step ${unlocked?'done':'locked'} ${currentClass}">
    <b>${i+1}. ${l.name}</b><br>
    <small>${unlocked?'Desbloqueado com '+l.xp+' XP':'Desbloqueia com '+l.xp+' XP'}</small>
    <div class="progress-line"><span style="width:${localProgress}%"></span></div>
    <small>${unlocked?'100':localProgress}%</small>
   </div>
  `;
 }).join('');
}
function renderJourney(){let i=state.journeyIndex||0,p=journeyPages[i];journeyContent.innerHTML=`<div class="journey-slide"><div class="journey-emoji">${p.emoji}</div><h3>${p.title}</h3><p>${p.text}</p><small>${i+1} de ${journeyPages.length}</small></div>`;journeyPrev.disabled=i===0;journeyNext.textContent=i===journeyPages.length-1?'Começar 🚀':'Próximo ▶'}
function approve(){
 let s=stats();
 if(!s.complete){
  approval.textContent='A missão ainda não está completa.';
  return;
 }
 if(state.money[today()]){
  approval.textContent='Missão já aprovada hoje.';
  renderAchievements();
  return;
 }
 state.money[today()]=10;
 state.xp=Number(state.xp||0)+10;
 state.piggy=state.piggy||{free:0,saved:0,charity:0};
 state.piggy.free=Number(state.piggy.free||0)+7;
 state.piggy.saved=Number(state.piggy.saved||0)+2;
 state.piggy.charity=Number(state.piggy.charity||0)+1;
 state.aiPlan='';
 save();
 approval.textContent='🦅 Missão aprovada. R$ 10 liberados. +10 XP.';
 renderAll();
 setTimeout(renderAchievements,100);
}
function renderAll(){renderMission();renderEagleMessage();renderAnnual();renderCatechism();renderAcademy();renderGradesTable();renderAcademyStats();renderAchievements();renderJourney();weekMoney.textContent=money(weekMoneyTotal());xp.textContent=Number(state.xp||0)+' XP';renderBackupStatus&&renderBackupStatus()}
async function runOCR(file){ocrStatus.textContent='Processando arquivo...';let url=URL.createObjectURL(file);reportPreview.innerHTML=file.type.includes('pdf')?`<iframe src="${url}"></iframe>`:`<img src="${url}" alt="Boletim">`;if(file.type.startsWith('image/') && window.Tesseract){ocrStatus.textContent='Lendo imagem com OCR. Isso pode demorar...';let res=await Tesseract.recognize(file,'por+eng');ocrText.value=res.data.text;state.lastOCR=res.data.text;save();ocrStatus.textContent='OCR concluído. Revise o texto e clique em detectar notas.';return}ocrStatus.textContent='Arquivo carregado. Para OCR automático, prefira imagem nítida do boletim.'}
document.addEventListener('change',e=>{if(e.target.matches('#tasks input')){state.checked[e.target.dataset.id]=e.target.checked;state.aiPlan='';save();renderAll()}if(e.target.matches('[data-grade-sub]')){let s=e.target.dataset.gradeSub,i=Number(e.target.dataset.gradeI);state.grades[s][i]=Number(e.target.value||0);save();renderGradesTable();}if(e.target.id==='disciplineSelect'){state.selectedSubject=e.target.value;state.academySession=null;save();renderSelectedCurriculum(e.target.value);renderAcademySession()}if(e.target.id==='reportFile'){let file=e.target.files[0];if(file)runOCR(file)}if(e.target.id==='importGrades'){let file=e.target.files[0];if(!file)return;let r=new FileReader();r.onload=()=>{try{state.grades=JSON.parse(r.result);save();renderGradesTable();alert('Boletim importado.')}catch(e){alert('Arquivo inválido.')}};r.readAsText(file)}});
document.addEventListener('input',e=>{if(e.target.id==='cateSearch')renderCateSearch()});
document.addEventListener('click',e=>{if(e.target.matches('[data-tab]'))switchTab(e.target.dataset.tab);if(e.target.id==='goParent')switchTab('parent');if(e.target.id==='approve')approve();if(e.target.id==='parseGrades'){let found=parseGradesFromText(ocrText.value);let count=applyDetectedGrades(found);parseResult.innerHTML=count?`Notas detectadas e aplicadas: ${count}. Revise a tabela.`:'Nenhuma nota detectada automaticamente. Revise o texto ou preencha manualmente.'}if(e.target.id==='resetQuestionHistory'){state.seenQuestions={};state.academySession=null;save();alert('Histórico reiniciado.')}if(e.target.id==='startAcademySession'){startAcademySession();}if(e.target.id==='smartQuestion'){state.selectedSubject=smartPriority();state.academySession=null;save();renderAcademy();}if(e.target.matches('[data-annual]'))describeDate(e.target.dataset.annual);if(e.target.matches('[data-open-date-cate]')){let key=e.target.dataset.openDateCate;let idx=saturdaysOfYear().findIndex(d=>iso(d)===key);state.catePage=idx>=0?idx:cateWeekIndex(new Date(key+'T00:00:00'));save();switchTab('catechism')}if(e.target.matches('[data-open-cate]')){state.catePage=Number(e.target.dataset.openCate);state.aiPlan='';save();switchTab('catechism')}if(e.target.matches('[data-subject]'))showQuestion(e.target.dataset.subject);if(e.target.matches('.answer-session')){answerAcademySession(e.target.dataset.i);}if(e.target.matches('.answer')){let sub=e.target.dataset.sub,q=questionBank[sub][Number(e.target.dataset.qi)],ok=Number(e.target.dataset.i)===q[2];e.target.classList.add(ok?'correct':'wrong');state.xp+=ok?5:0;state.academyStats[sub]=state.academyStats[sub]||{correct:0,total:0};state.academyStats[sub].total++;if(ok)state.academyStats[sub].correct++;let fb=e.target.parentElement.querySelector('.feedback');fb.classList.remove('hidden');fb.textContent=ok?'✅ Correto! +5 XP':'❌ '+q[3];save();renderAcademyStats();}if(e.target.id==='continueCatechism'){state.catePage=cateWeekIndex();save();switchTab('catechism')}if(e.target.id==='prevCate'){state.catePage=Math.max(0,(state.catePage||0)-1);save();renderAll()}if(e.target.id==='nextCate'){state.catePage=Math.min(51,(state.catePage||0)+1);save();renderAll()}if(e.target.id==='favCate'){let i=state.catePage||0;state.cateFavorites=state.cateFavorites.includes(i)?state.cateFavorites.filter(x=>x!==i):[...state.cateFavorites,i];save();renderAll()}if(e.target.id==='markCate'){let i=state.catePage||0,key=iso(saturdaysOfYear()[i]);if(!state.cateDone[key]){state.cateDone[key]=true;state.cateXP+=10;state.xp+=10;save()}renderAll()}if(e.target.id==='journeyNext'){if(state.journeyIndex<journeyPages.length-1){state.journeyIndex++;save();renderJourney()}else switchTab('today')}if(e.target.id==='journeyPrev'){if(state.journeyIndex>0){state.journeyIndex--;save();renderJourney()}}if(e.target.id==='restartJourney'){state.journeyIndex=0;save();renderJourney()}if(e.target.id==='saveGrades'){save();alert('Notas salvas e sincronizadas com o responsável.')}if(e.target.id==='exportGrades'){let blob=new Blob([JSON.stringify(state.grades,null,2)],{type:'application/json'});let a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='boletim-projeto-aguia.json';a.click()}if(e.target.id==='export'){let blob=new Blob([JSON.stringify(state,null,2)],{type:'application/json'});let a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='projeto-aguia-v23-progresso.json';a.click()}if(e.target.id==='logout'){localStorage.removeItem('unlockedV23');location.reload()}});
